SELECT id, unit_id, user_id, attendance_date, check_in_time, check_out_time, check_in_result, check_in_fail_reason, check_in_address, check_out_address FROM attendance_record WHERE user_id IN
#{item}
AND attendance_date >= CAST(#{startDate} AS date) AND attendance_date <= CAST(#{endDate} AS date) AND valid_flag = 1 ORDER BY attendance_date DESC, id DESC
